-- Dumping structure for procedure email_dispatcher.check_email_suppressed
DROP PROCEDURE IF EXISTS `check_email_suppressed`;
DELIMITER //
CREATE PROCEDURE `check_email_suppressed`(
    IN p_email VARCHAR(255)
)
BEGIN
    SELECT 
        sl.type,
        sl.reason,
        sl.created_at,
        CASE 
            WHEN sl.expires_at IS NOT NULL AND sl.expires_at < NOW() THEN 0
            ELSE 1
        END as is_active
    FROM suppression_list sl
    WHERE sl.email = p_email
    LIMIT 1;
END//
DELIMITER ;

-- Dumping structure for procedure email_dispatcher.cleanup_old_jobs
DROP PROCEDURE IF EXISTS `cleanup_old_jobs`;
DELIMITER //
CREATE PROCEDURE `cleanup_old_jobs`(IN days_old INT)
BEGIN
    -- Delete mail_job_items for old completed/failed jobs
    DELETE FROM mail_job_items 
    WHERE mail_job_id IN (
        SELECT id FROM mail_jobs 
        WHERE (status = 'completed' OR status = 'failed')
        AND created_at < DATE_SUB(NOW(), INTERVAL days_old DAY)
    );
    
    -- Delete old completed/failed mail_jobs
    DELETE FROM mail_jobs 
    WHERE (status = 'completed' OR status = 'failed')
    AND created_at < DATE_SUB(NOW(), INTERVAL days_old DAY);
    
    -- Return success message
    SELECT 'Cleanup completed successfully' as message;
END//
DELIMITER ;

