-- Dumping structure for procedure email_dispatcher.get_job_analytics
DROP PROCEDURE IF EXISTS `get_job_analytics`;
DELIMITER //
CREATE PROCEDURE `get_job_analytics`(
    IN p_job_id INT
)
BEGIN
    SELECT 
        event_type,
        COUNT(*) as count,
        COUNT(DISTINCT email) as unique_count
    FROM email_analytics
    WHERE mail_job_id = p_job_id
    GROUP BY event_type
    ORDER BY count DESC;
END//
DELIMITER ;

