REPLACE INTO `email_templates` (`id`, `name`, `description`, `body`, `template_type`, `created_by`, `created_at`, `updated_at`) VALUES
	(5, 'Template Default - Professional', 'Template standar profesional', '<h2>Subject Email Anda</h2><p>Kepada yang terhormat,</p><p>Berikut adalah informasi yang Anda minta:</p><p>---</p><p>Terima kasih atas perhatian Anda.</p><p>Salam hormat,<br/>Tim</p>', 'standalone', 5, '2026-03-06 15:56:24', '2026-03-06 15:56:24'),
	(6, 'Template Pengumuman - Resmi', 'Template untuk pengumuman resmi', '<h2>PENGUMUMAN PENTING</h2><p>Kepada semua pihak yang bersangkutan,</p><p><strong>Berikut informasi penting yang perlu Anda ketahui:</strong></p><ul><li>Poin pertama</li><li>Poin kedua</li><li>Poin ketiga</li></ul><p>Perhatikan baik-baik informasi di atas.</p><p>Demikian untuk diketahui.</p>', 'standalone', 5, '2026-03-06 15:56:24', '2026-03-06 15:56:24'),
	(7, 'Template Laporan - Bulanan', 'Template untuk laporan bulanan', '<h2>LAPORAN BULAN [BULAN/TAHUN]</h2><p>Dengan hormat,</p><p>Berikut adalah laporan untuk periode [PERIODE]:</p><table style="width:100%; border-collapse: collapse; border: 1px solid #ccc;"><tr style="background: #f0f0f0;"><th style="border: 1px solid #ccc; padding: 8px;">Item</th><th style="border: 1px solid #ccc; padding: 8px;">Total</th></tr><tr><td style="border: 1px solid #ccc; padding: 8px;">Keterangan</td><td style="border: 1px solid #ccc; padding: 8px;">0</td></tr></table><p><strong>Total Keseluruhan: 0</strong></p><p>Terima kasih.</p>', 'standalone', 5, '2026-03-06 15:56:24', '2026-03-06 15:56:24'),
	(8, 'Order LSP', 'Template Email Order LSP', '<p><strong style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);"><em>Dear Supplier ADM KAP</em></strong></p><p><br></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">Selamat Pagi,</span></p><p><br></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">Berikut kami informasikan data summary order untuk delivery tanggal .........., DN dapat didownload pada jam ....... wib.</span></p><p><br></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">1. Mohon dilakukan cross check terlebih dahulu antara summary terlampir dengan DN hasil&nbsp;download dari WEB.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">2. Mohon konfirmasinya apabila ada perbedaan antara data yang ada di summary DN dengan hasil download WEB.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">3. Apabila ada kendala dalam proses download EDN kami tunggu segera untuk konfirmasinya.</span></p><p><br></p><p><strong style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);"><em>Password : adm</em></strong></p><p><br></p><p><em style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">PIC Ordering :</em></p><p><em style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">1.&nbsp;</em><em style="background-color: rgb(255, 255, 255); color: inherit;">Furqon</em><em style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">&nbsp;Permata Bumi&nbsp;&nbsp;: 0856-9377-8891 (Non Shift)</em></p><p><em style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">2. Aji Prasetyo &nbsp;: 0819-0412-7762 (Non Shift)</em></p><p><br></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">Demikian informasi ini kami sampaikan, atas perhatiannya kami ucapkan terima kasih.</span></p><p><br></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">Regards,</span></p><p><span style="background-color: rgb(255, 255, 255); color: inherit;">Furqon</span><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">&nbsp;Permata Bumi (Mr)</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">PT. Astra Daihatsu Motor Karawang Assembly Plant</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">Plant Administration Division, Ordering section</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">Hp / WA 0856-9377-8891</span></p><p><br></p>', 'group_order', 5, '2026-03-06 16:00:09', '2026-03-06 16:00:09'),
	(9, 'Order Consumable', 'Template order daily order consumable', '<p><strong style="background-color: rgb(255, 255, 255); color: inherit;"><em>Dear Supplier ADM KAP,</em></strong><em style="background-color: rgb(255, 255, 255); color: rgb(31, 73, 125);">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</em></p><p><span style="background-color: rgb(255, 255, 255); color: inherit;">Berikut kami informasikan Delivery Note ADM KAP.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(0, 0, 204);">"Terlampir di attachment sheet&nbsp;dengan Password" :&nbsp;</span><strong style="background-color: rgb(255, 255, 255); color: rgb(0, 0, 204);"><em><u>adm</u></em></strong></p><p><strong style="background-color: rgb(255, 255, 255); color: rgb(31, 73, 125);">Mohon perhatikan dan persiapkan sebelum pengiriman barang sebagai berikut :</strong></p><ol><li data-list="ordered"><span class="ql-ui" contenteditable="false"></span><span style="background-color: rgb(255, 255, 255); color: inherit;">Pastikan DN diprint dan dibawa beserta surat jalan supplier.</span></li><li data-list="ordered"><span class="ql-ui" contenteditable="false"></span><span style="background-color: rgb(255, 255, 255); color: inherit;">Pengiriman dapat menyesuaikan tanggal dan jam yang tertera pada DN ( Apabila ada perubahan mohon dikonfirmasikan terlebih dahulu ke team Warehose Consumable ).</span></li><li data-list="ordered"><span class="ql-ui" contenteditable="false"></span><span style="background-color: rgb(255, 255, 255); color: inherit;">Pastikan pengiriman sudah terdaftar dan sudah mengisi Form Deklarasi Kesehatan yang sudah dikonfirm/disetujui management ADM.</span></li></ol><p><strong style="background-color: lime; color: red;">PIC PO &amp; DN</strong></p><ol><li data-list="ordered"><span class="ql-ui" contenteditable="false"></span><strong style="background-color: rgb(255, 255, 255); color: inherit;">Isna Ariwibowo </strong><span style="background-color: rgb(255, 255, 255); color: inherit;">( 08121000607 /&nbsp;</span><a href="mailto:isna.ariwibowo@daihatsu.astra.co.id" rel="noopener noreferrer" target="_blank" style="background-color: rgb(255, 255, 255); color: rgb(51, 102, 204);">isna.ariwibowo@daihatsu.astra.co.id</a><span style="background-color: rgb(255, 255, 255); color: inherit;">&nbsp;)</span></li><li data-list="ordered"><span class="ql-ui" contenteditable="false"></span><strong style="background-color: rgb(255, 255, 255); color: inherit;">Edi Murtopo </strong><span style="background-color: rgb(255, 255, 255); color: inherit;">( 081380142645 /&nbsp;</span><a href="mailto:edi.murtopo@daihatsu.astra.co.id" rel="noopener noreferrer" target="_blank" style="background-color: rgb(255, 255, 255); color: inherit;">edi.murtopo@daihatsu.astra.co.id</a><span style="background-color: rgb(255, 255, 255); color: inherit;">&nbsp;)</span></li><li data-list="ordered"><span class="ql-ui" contenteditable="false"></span><strong style="background-color: rgb(255, 255, 255); color: inherit;">Totoh faturohman </strong><span style="background-color: rgb(255, 255, 255); color: inherit;">(&nbsp;</span><span style="background-color: rgb(255, 255, 255); color: rgb(31, 73, 125);">089682524947</span><span style="background-color: rgb(255, 255, 255); color: inherit;">&nbsp;/&nbsp;</span><a href="mailto:totoh.faturohman@daihatsu.astra.co.id" rel="noopener noreferrer" target="_blank" style="background-color: rgb(255, 255, 255); color: inherit;">totoh.faturohman@daihatsu.astra.co.id</a><span style="background-color: rgb(255, 255, 255); color: inherit;">&nbsp;)</span></li></ol><p><strong style="background-color: yellow; color: red;">PIC Warehouse ( Receiving )</strong></p><ol><li data-list="ordered"><span class="ql-ui" contenteditable="false"></span><strong style="background-color: rgb(255, 255, 255); color: windowtext;">Yari </strong><strong style="background-color: rgb(255, 255, 255); color: inherit;">(082233556370)</strong></li><li data-list="ordered"><span class="ql-ui" contenteditable="false"></span><strong style="background-color: rgb(255, 255, 255); color: inherit;">Zarfain </strong><span style="background-color: rgb(255, 255, 255); color: inherit;">( 089635825921 )</span></li></ol><p><strong style="background-color: rgb(255, 255, 255); color: inherit;">Regards</strong></p><p><strong style="background-color: rgb(255, 255, 255); color: inherit;">EDI MURTOPO</strong></p><p><span style="background-color: rgb(255, 255, 255); color: red;">Ordering Consummable &amp; Admin</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(0, 176, 80);">PLANNING CONTROL DEPT</span></p><p><strong style="background-color: rgb(255, 255, 255); color: inherit;">PT. Astra Daihatsu Motor – Karawang Assembly Plant (KAP)</strong></p><p><span style="background-color: rgb(255, 255, 255); color: inherit;">Jl.&nbsp;Surya Pratama Kav.1 no 47-57. Kawasan Industri Surya Cipta, Karawang Timur - Indonesia.</span></p><p><span style="background-color: rgb(255, 255, 255); color: inherit;">41361</span></p><p><span style="background-color: rgb(255, 255, 255); color: inherit;">No Hp 081380142645</span></p><p><span style="background-color: rgb(255, 255, 255); color: inherit;">Email :&nbsp;</span><a href="mailto:Edi.murtopo@daihatsu.astra.co.id" rel="noopener noreferrer" target="_blank" style="background-color: rgb(255, 255, 255); color: inherit;">Edi.murtopo@daihatsu.astra.co.id</a></p><p><br></p>', 'group_order', 5, '2026-03-06 16:02:36', '2026-03-13 08:16:35'),
	(10, 'PO MTC', 'PO Approval based on PR Maintenance', '<p><strong style="color: black;">Dear </strong></p><p>Selamat Siang,</p><p>Sebelumnya kami ucapkan terimakasih atas kejasamanyayang terjalin selama ini. Berikut kami kirimkan&nbsp;Purchase Order ADM KAP Dengan Nomor  :</p><p><strong style="color: black;"><u>PIC Penerima Barang/Jasa :</u></strong></p><p><strong>Nama :&nbsp;Bp. Hikmah /Bp. Sugeng/ Bp. Sakti</strong></p><p><strong>Area&nbsp;&nbsp;:&nbsp;WH Maintenance</strong></p><p><strong style="color: black;">Catatan :&nbsp;</strong></p><p><strong style="color: black;">①</strong><strong style="color: rgb(31, 73, 125);">. </strong><strong style="color: black; background-color: yellow;">Mohon mereply email dengan format Tabel berikut pada Body email</strong><strong style="color: black;">&nbsp;:</strong></p><table><tbody><tr><td data-row="1">No</td><td data-row="1">PO</td><td data-row="1">Status PO [Proses/Reject]</td><td data-row="1">Material</td><td data-row="1">Number</td><td data-row="1">Material Name</td><td data-row="1">Qty</td><td data-row="1">D/D Delivery</td><td data-row="1">Stock</td><td data-row="1">[Ready/Indent]</td><td data-row="1">PIC &amp; C/P</td><td data-row="1">[Supplier]</td><td data-row="1">Remark</td></tr><tr><td data-row="2">&nbsp;</td><td data-row="2">&nbsp;</td><td data-row="2">&nbsp;</td><td data-row="2">&nbsp;</td><td data-row="2">&nbsp;</td><td data-row="2">&nbsp;</td><td data-row="2">&nbsp;</td><td data-row="2">&nbsp;</td><td data-row="2">&nbsp;</td><td data-row="2">&nbsp;</td><td data-row="2">&nbsp;</td><td data-row="2">&nbsp;</td><td data-row="2">&nbsp;</td></tr><tr><td data-row="3">&nbsp;</td><td data-row="3">&nbsp;</td><td data-row="3">&nbsp;</td><td data-row="3">&nbsp;</td><td data-row="3">&nbsp;</td><td data-row="3">&nbsp;</td><td data-row="3">&nbsp;</td><td data-row="3">&nbsp;</td><td data-row="3">&nbsp;</td><td data-row="3">&nbsp;</td><td data-row="3">&nbsp;</td><td data-row="3">&nbsp;</td><td data-row="3">&nbsp;</td></tr><tr><td data-row="4">&nbsp;</td><td data-row="4">&nbsp;</td><td data-row="4">&nbsp;</td><td data-row="4">&nbsp;</td><td data-row="4">&nbsp;</td><td data-row="4">&nbsp;</td><td data-row="4">&nbsp;</td><td data-row="4">&nbsp;</td><td data-row="4">&nbsp;</td><td data-row="4">&nbsp;</td><td data-row="4">&nbsp;</td><td data-row="4">&nbsp;</td><td data-row="4">&nbsp;</td></tr></tbody></table><p><strong><em>Pasword : adm</em></strong></p><p><strong style="background-color: yellow; color: rgb(0, 0, 204);">PENTING :</strong></p><p><strong style="color: rgb(0, 0, 204);">( <u>Cek PO sebelum barang dikirimkan agar tidak menghambat proses penagihan/pembayaran ADM ke supplier</u>&nbsp;) :</strong></p><p><strong style="color: rgb(0, 0, 204);">1.</strong><span style="color: rgb(0, 0, 204);">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span><strong style="color: rgb(0, 0, 204);">Kategori supplier PPN atau Non PPN.</strong></p><p><strong style="color: rgb(0, 0, 204);">2.</strong><span style="color: rgb(0, 0, 204);">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span><strong style="color: rgb(0, 0, 204);">Kelengkapan tanda tangan PO.</strong></p><p><strong style="color: rgb(0, 0, 204);">3.</strong><span style="color: rgb(0, 0, 204);">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span><strong style="color: rgb(0, 0, 204);">Item lain/kelengkapan yg diperlukan supplier (DN dll).</strong></p><p><strong style="color: rgb(0, 0, 204);">4.</strong><span style="color: rgb(0, 0, 204);">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span><strong style="color: rgb(0, 0, 204);">Apabila ada yg kurang jelas dan tidak sesuai mohon dapat segera konfirmasi kembali.</strong></p><p><strong style="background-color: yellow; color: black;"><em>Mohon konfirmasinya (reply email) sebagai tanda PO sudah diterima.</em></strong></p><p>Demikian informasinya, atas segala perhatian &amp; kerjasamanya kami ucapkan terima kasih.</p><p><strong>Regards,</strong></p><p><strong>Aji Prasetyo</strong></p><p>Ordering ADM KAP</p><p>Phone : 081904127762</p><p><br></p><p><br></p><p><br></p>', 'group_order', 5, '2026-03-09 14:31:00', '2026-04-28 10:18:01'),
	(11, 'PO BULANAN CONSUMABLE', 'Template Email PO Bulanan Consumable ADM KAP', '<p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">Dear Supplier,</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">Berikut kami informasikan&nbsp;</span><span style="background-color: rgb(255, 255, 255); color: inherit;">PO</span><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">&nbsp;</span><span style="background-color: rgb(255, 255, 255); color: inherit;">CONSUMABLE</span><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">&nbsp;ADM KAP </span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">Terlampir di attachment sheet dengan Password : adm</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">Untuk penarikan order harian melalui DN, Mohon perhatikan dan persiapkan sebelum pengiriman barang sebagai berikut</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">1.&nbsp;Pastikan DN diprint dan dibawa beserta surat jalan supplier.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">2.&nbsp;Pengiriman dapat menyesuaikan tanggal dan jam yang tertera pada DN (Apabila ada perubahan mohon dikonfirmasikan terlebih dahulu ke team Warehose&nbsp;</span><span style="background-color: rgb(255, 255, 255); color: inherit;">Consumable</span><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">).</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">3.&nbsp;Pastikan pengiriman sudah terdaftar dan sudah mengisi Form Deklarasi Kesehatan yang sudah dikonfirm/disetujui management ADM.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">PIC&nbsp;</span><span style="background-color: rgb(255, 255, 255); color: inherit;">PO</span><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">&nbsp;&amp; DN</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">1. Aji Prasetyo</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">(081904127762 /&nbsp;</span><u style="background-color: rgb(255, 255, 255); color: rgb(5, 99, 193);"><a href="mailto:aji.prasetyo@daihatsu.astra.co.id" rel="noopener noreferrer" target="_blank">aji.prasetyo@daihatsu.astra.co.id</a></u><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">)</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">2. Edi murtopo</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">(081380142645 /&nbsp;</span><u style="background-color: rgb(255, 255, 255); color: rgb(5, 99, 193);"><a href="mailto:edi.murtopo@daihatsu.astra.co.id" rel="noopener noreferrer" target="_blank">edi.murtopo@daihatsu.astra.co.id</a></u><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">)</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">3. Isna Ariwibowo</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">(081210000607 /&nbsp;</span><u style="background-color: rgb(255, 255, 255); color: rgb(5, 99, 193);"><a href="mailto:isna.ariwibowo@daihatsu.astra.co.id" rel="noopener noreferrer" target="_blank">isna.ariwibowo@daihatsu.astra.co.id</a></u><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">)</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">&nbsp;PIC Warehouse (Receiving)</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(36, 36, 36);">1. Yari (082233556370 /&nbsp;</span><u style="background-color: rgb(255, 255, 255); color: rgb(5, 99, 193);"><a href="mailto:Yari.Agiesta@Daihatsu.astra.co.id" rel="noopener noreferrer" target="_blank">Yari